import{_ as e,o as t,c as n,j as r,a as s,a1 as b}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"百臂巨人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/百臂巨人.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/百臂巨人.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/百臂巨人.md"};function d(i,a,l,_,p,c){return t(),n("div",null,[...a[0]||(a[0]=[r("h1",{id:"百臂巨人",tabindex:"-1"},[s("百臂巨人 "),r("a",{class:"header-anchor",href:"#百臂巨人","aria-label":'Permalink to "百臂巨人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),b('<h1 id="百臂巨人-1" tabindex="-1">百臂巨人 <a class="header-anchor" href="#百臂巨人-1" aria-label="Permalink to &quot;百臂巨人&quot;">​</a></h1><p>【百臂巨人】<br> B+2000<br> 它们是巨人，有五十颗头颅，一百只手臂，长相丑陋而力大无穷，凶猛而巨大的怪物——<br> 它们的本质，是带来决定性胜利的庞然巨物<br> 你获得一张由青铜弓和一只青铜手臂组成的长弓，它坚实，可靠，并且肌肉的纹理明显。<br> 武器伤害：18L<br> 基础：【高速3】【破甲1】【双手】【无速射】<br> 体积：3<br> 装弹量：1<br> 基础射程：40米<br> 持有此弓会使得你拥有百手巨人之力<br> 【κατν（一百）χερ（手）】<br> Centimani，前第马尼<br> 向他们投出百块山石<br> 你射出的箭矢将如巨石一般沉重，以这个武器造成的攻击伤害转为物理-钝击。<br> 并且，每当你以百臂巨人战胜3名同级敌人时，弓身上将出现一只额外的手臂，这些手臂不提供抓握等功能，只是在你攻击时，它们将额外向其他敌人投掷出攻击力相当的巨石——你可以以百臂巨人上的手臂数量的新增一个其他攻击目标效果，上限98，初始即拥有1只手臂。<br> 【κατγχειρε（百臂巨人）】<br> 百手的巨人啊，为我带来胜利<br> 手持此弓时，你可以选择一个自由动作引动与关闭百臂巨人的力量<br> 变为百臂巨人时，会使得你的体型在你的内在等级为b/a/s时获得9/12/15点体积，这些体积不会提供生命值上的加成，如虚拟体积般计算。<br> 同时，弓体上的手臂们将进行解体并附着在你的双手手臂上，当你做出拉弓的动作时，它们也将帮助你进行蓄力，这会使得你的力量射击在你的内在等级为b/a/s时获得9/12/15点增强加值，此时百臂巨人依旧占据你的双手武器位。<br> 力量的出色也会使得你能够将攻击投射到更远的地方，你在力量射击时额外获得60米的额外射程。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=e(o,[["render",d]]);export{f as __pageData,m as default};
